#include <stdio.h>
#include <string.h>

#define TARGET 50000

char cur[20];
char result[TARGET][20];
int resCnt = 0;

void dfs(int pos, int len) {
    if (resCnt >= TARGET) return;
    if (pos == len) {
        int c8 = 0, c5 = 0, c3 = 0;
        for (int i = 0; i < len; ++i) {
            if (cur[i] == '8') c8++;
            else if (cur[i] == '5') c5++;
            else c3++;
        }
        if (c8 >= c5 && c5 >= c3) {
            cur[len] = '\0';
            strcpy(result[resCnt++], cur);
        }
        return;
    }
    cur[pos] = '3'; dfs(pos + 1, len); if (resCnt >= TARGET) return;
    cur[pos] = '5'; dfs(pos + 1, len); if (resCnt >= TARGET) return;
    cur[pos] = '8'; dfs(pos + 1, len);
}

int main() {
    for (int len = 1; resCnt < TARGET; ++len) {
        dfs(0, len);
    }
    for (int i = 0; i < TARGET; ++i) {
        puts(result[i]);
    }
    return 0;
}

