import java.util.*;

public class Main {
    private static final int TARGET = 50000;
    private static final List<String> ans = new ArrayList<>(TARGET);
    private static final StringBuilder cur = new StringBuilder();

    private static void dfs(int len) {
        if (ans.size() >= TARGET) return;
        if (cur.length() == len) {
            int c8 = 0, c5 = 0, c3 = 0;
            for (int i = 0; i < len; i++) {
                char ch = cur.charAt(i);
                if (ch == '8') c8++;
                else if (ch == '5') c5++;
                else c3++;
            }
            if (c8 >= c5 && c5 >= c3) ans.add(cur.toString());
            return;
        }
        for (char d : new char[]{'3', '5', '8'}) {
            cur.append(d);
            dfs(len);
            cur.setLength(cur.length() - 1);
            if (ans.size() >= TARGET) return;
        }
    }

    public static void main(String[] args) {
        for (int len = 1; ans.size() < TARGET; len++) {
            dfs(len);
        }
        StringBuilder out = new StringBuilder();
        for (String s : ans) out.append(s).append('\n');
        System.out.print(out.toString());
    }
}

