#!/usr/bin/env python3
import sys

def generate():
    TARGET = 50000
    ans = []
    cur = []
    def dfs(length):
        if len(ans) >= TARGET:
            return
        if len(cur) == length:
            c8 = cur.count('8')
            c5 = cur.count('5')
            c3 = cur.count('3')
            if c8 >= c5 >= c3:
                ans.append(''.join(cur))
            return
        for d in ('3', '5', '8'):
            cur.append(d)
            dfs(length)
            cur.pop()
            if len(ans) >= TARGET:
                return
    length = 1
    while len(ans) < TARGET:
        dfs(length)
        length += 1
    return ans

if __name__ == "__main__":
    out = generate()
    sys.stdout.write('\n'.join(out))
    sys.stdout.write('\n')

